import { useUser } from '@fs/zion-user'
import CacheService, { useCacheService } from '@fs/zion-cache-service'
import { useMemo } from 'react'
import { formatAuthorizedImageUrl, artifactStoreUrl } from './profile'

type PortraitData = {
  thumb200Uri?: string
  thumb200sUri?: string
  avatarUrl: string
}

type PortraitResponse = {
  loading?: boolean
  data?: PortraitData
  error?: Error
}

const cacheService = new CacheService({
  cache: { type: 'session', storeName: 'portrait', dbName: 'fs' },
})

/**
 * Hook for retrieving the user's portrait data and deriving an avatar URL. It uses a cache service to fetch the portrait artifact for the current user, defaults to session storage.
 */
export const usePortraitService = (
  cacheConfig: CacheService = cacheService
): [PortraitResponse, () => PortraitResponse] => {
  const { cisId, userLoading, signedIn } = useUser()

  const url: URL = useMemo(() => {
    const newUrl = new URL(artifactStoreUrl, window.location.origin)
    newUrl.searchParams.set('cisId', cisId)
    return newUrl
  }, [cisId])

  const response = useCacheService(cacheConfig, url.toString(), `user-${cisId}`, {
    manual: userLoading || !signedIn,
  })
  const avatarUrl = formatAuthorizedImageUrl(response[0].data?.thumb200Uri || response[0].data?.thumb200sUri)

  return [{ ...response[0], data: { ...response[0].data, avatarUrl } }, response[1]]
}
